#include "syntax.h"

#include <stdlib.h>
#include <string.h>

#include "tree_sitter/api.h"

// Generated by the vendored tree-sitter-c parser source.
extern const TSLanguage *tree_sitter_c(void);

struct editorSyntaxState {
	enum editorSyntaxLanguage language;
	TSParser *parser;
	TSTree *tree;
};

static int editorSyntaxLengthFitsTreeSitter(size_t len) {
	return len <= UINT32_MAX;
}

static const TSLanguage *editorSyntaxLanguageObject(enum editorSyntaxLanguage language) {
	switch (language) {
		case EDITOR_SYNTAX_C:
			return tree_sitter_c();
		case EDITOR_SYNTAX_NONE:
		default:
			return NULL;
	}
}

enum editorSyntaxLanguage editorSyntaxDetectLanguageFromFilename(const char *filename) {
	if (filename == NULL || filename[0] == '\0') {
		return EDITOR_SYNTAX_NONE;
	}

	const char *dot = strrchr(filename, '.');
	if (dot == NULL) {
		return EDITOR_SYNTAX_NONE;
	}
	if (strcmp(dot, ".c") == 0 || strcmp(dot, ".h") == 0) {
		return EDITOR_SYNTAX_C;
	}
	return EDITOR_SYNTAX_NONE;
}

struct editorSyntaxState *editorSyntaxStateCreate(enum editorSyntaxLanguage language) {
	const TSLanguage *ts_language = editorSyntaxLanguageObject(language);
	if (ts_language == NULL) {
		return NULL;
	}

	struct editorSyntaxState *state = malloc(sizeof(*state));
	if (state == NULL) {
		return NULL;
	}
	state->language = language;
	state->parser = ts_parser_new();
	state->tree = NULL;
	if (state->parser == NULL) {
		free(state);
		return NULL;
	}
	if (!ts_parser_set_language(state->parser, ts_language)) {
		ts_parser_delete(state->parser);
		free(state);
		return NULL;
	}

	return state;
}

void editorSyntaxStateDestroy(struct editorSyntaxState *state) {
	if (state == NULL) {
		return;
	}
	if (state->tree != NULL) {
		ts_tree_delete(state->tree);
	}
	if (state->parser != NULL) {
		ts_parser_delete(state->parser);
	}
	free(state);
}

int editorSyntaxStateParseFull(struct editorSyntaxState *state, const char *source, size_t len) {
	if (state == NULL || state->parser == NULL || source == NULL || !editorSyntaxLengthFitsTreeSitter(len)) {
		return 0;
	}

	TSTree *new_tree = ts_parser_parse_string(state->parser, NULL, source, (uint32_t)len);
	if (new_tree == NULL) {
		return 0;
	}

	if (state->tree != NULL) {
		ts_tree_delete(state->tree);
	}
	state->tree = new_tree;
	return 1;
}

int editorSyntaxStateApplyEditAndParse(struct editorSyntaxState *state,
		const struct editorSyntaxEdit *edit,
		const char *source,
		size_t len) {
	if (state == NULL || state->parser == NULL || state->tree == NULL || edit == NULL ||
			source == NULL || !editorSyntaxLengthFitsTreeSitter(len)) {
		return 0;
	}

	TSInputEdit ts_edit = {
		.start_byte = edit->start_byte,
		.old_end_byte = edit->old_end_byte,
		.new_end_byte = edit->new_end_byte,
		.start_point = {.row = edit->start_point.row, .column = edit->start_point.column},
		.old_end_point = {.row = edit->old_end_point.row, .column = edit->old_end_point.column},
		.new_end_point = {.row = edit->new_end_point.row, .column = edit->new_end_point.column},
	};
	ts_tree_edit(state->tree, &ts_edit);

	TSTree *new_tree = ts_parser_parse_string(state->parser, state->tree, source, (uint32_t)len);
	if (new_tree == NULL) {
		return 0;
	}

	ts_tree_delete(state->tree);
	state->tree = new_tree;
	return 1;
}

int editorSyntaxStateHasTree(const struct editorSyntaxState *state) {
	return state != NULL && state->tree != NULL;
}

const char *editorSyntaxStateRootType(const struct editorSyntaxState *state) {
	if (!editorSyntaxStateHasTree(state)) {
		return NULL;
	}

	TSNode root = ts_tree_root_node(state->tree);
	return ts_node_type(root);
}

enum editorSyntaxLanguage editorSyntaxStateLanguage(const struct editorSyntaxState *state) {
	if (state == NULL) {
		return EDITOR_SYNTAX_NONE;
	}
	return state->language;
}
